// One company per loop
const row = items[0].json;

// ---------- Helpers ----------
function yn(v) {
  const n = Number(v ?? 0);
  return n === 1 ? 'Yes' : 'No';
}

const slug = (row.slug || row.name)
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

// ---------- Markdown ----------
const md = [];

md.push(`# ${row.name} `);
md.push('');

md.push(`- **Source:** ${row.source || 'N/A'}`);
md.push(`- **Source ID:** ${row.source_id || 'N/A'}`);
md.push(`- **UEX Company ID:** ${row.uex_company_id || 'N/A'}`);
md.push(`- **Company Code:** ${row.company_code || 'N/A'}`);
md.push(`- **Nickname:** ${row.nickname || 'N/A'}`);
md.push(`- **Industry:** ${row.industry || 'N/A'}`);
md.push(`- **Item Manufacturer:** ${yn(row.is_item_manufacturer)}`);
md.push(`- **Vehicle Manufacturer:** ${yn(row.is_vehicle_manufacturer)}`);
md.push('');

if (row.wiki) {
  md.push(`- **Wiki:** ${row.wiki}`);
  md.push('');
}

md.push(`## Overview`);
md.push('');
md.push(
  `${row.name}${row.nickname && row.nickname !== row.name ? ` (“${row.nickname}”)` : ''}` +
  `${row.industry ? ` operates in **${row.industry}**.` : ' has no industry recorded.'}`
);
md.push('');

md.push(`## Manufacturer Flags`);
md.push('');
md.push(`| Flag | Value |`);
md.push(`|------|-------|`);
md.push(`| Item manufacturer | ${yn(row.is_item_manufacturer)} |`);
md.push(`| Vehicle manufacturer | ${yn(row.is_vehicle_manufacturer)} |`);
md.push('');

md.push(`## Notes`);
md.push('');
md.push('_No notes currently tracked._');

// ---------- Output only DETAILED ----------
const filePathDetailed = `/RAG/KB/misc/${slug}_detailed.md`;

return [
  {
    json: {
      company_id: row.id,
      slug,
      name: row.name,
      markdown_detailed: md.join('\n'),
      filePath_detailed: filePathDetailed,
    },
  },
];

