const item = $input.first().json;
const slug = (item.slug || '').replace(/'/g, "''");
const entityId = item.company_id || null;
const content = (item.markdown_detailed || '').replace(/'/g, "''");
const query = "INSERT INTO kb_content (entity_slug, entity_type, entity_id, content, source_workflow, generated_at, updated_at) VALUES ('" + slug + "', 'company', '" + entityId + "'::uuid, '" + content + "', 'KB - Company Markdown v2.2', now(), now()) ON CONFLICT (entity_slug, entity_type) DO UPDATE SET content = EXCLUDED.content, entity_type = EXCLUDED.entity_type, source_workflow = EXCLUDED.source_workflow, generated_at = EXCLUDED.generated_at, updated_at = now()";
return [{ json: { query, entity_slug: item.slug } }];
